+    for (unsigned J = 0; J != NumArgs; ++J)
+      if (isVectorIntrinsicWithScalarOpAtArg(ID, J, TTI))
+        ScalarArgs[J] = CI->getArgOperand(J);
+    for (Value *V : VL) {
